  async acquire(cb) {
    if (this.locked || this.acquiring) {
      throw new LoccoError("Lock is already acquired");
    }
    this.acquiring = true;
    try {
      await retry({
        settings: this.retrySettings,
        fn: () => this.adapter.createLock({
          key: this.key,
          uniqueValue: this.uniqueValue,
          ttl: this.ttl
        }),
        shouldProceedFn: (error) => error instanceof LockCreateError
      });
      this.locked = true;
    } catch (error) {
      this.acquiring = false;
      throw error;
    }
    if (isFunction(cb)) {
      try {
        return await cb(this);
      } finally {
        await this.release();
      }
    }
    return this;
  }
  async release({ throwOnFail = false } = {}) {
    try {
      if (this.released) {
        throw new LoccoError(
          "Locco:::Lock:::release Can't release resource twice"
        );
      }
      await this.adapter.releaseLock({
        key: this.key,
        uniqueValue: this.uniqueValue
      });
      this.released = true;
    } catch (error) {
      if (throwOnFail) {
        throw error;
      }
    }
  }
  async isLocked() {
    return this.adapter.isValidLock({
      key: this.key,
      uniqueValue: this.uniqueValue
    });
  }
